def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""

    # Group triples by their subject for richer sentence construction
    subject_map: dict[str, list[Triple]] = {}
    for t in triples:
        subject_map.setdefault(t.subject, []).append(t)

    sentences: list[str] = []

    # Helper to find extra information about a genre (or any object that appears as a subject)
    def extra_info_for(obj: str) -> list[str]:
        info = []
        for t in triples:
            if t.subject == obj:
                if t.predicate == "stylisticOrigin":
                    info.append(f"originated from {t.object}")
                elif t.predicate == "derivative":
                    info.append(f"has {t.object} as a derivative")
                elif t.predicate == "musicFusionGenre":
                    info.append(f"is fused with {t.object}")
                elif t.predicate == "musicSubgenre":
                    info.append(f"is a subgenre of {t.object}")
        return info

    for subj, tlist in subject_map.items():
        # Collect attribute phrases for this subject
        attrs: dict[str, str] = {t.predicate: t.object for t in tlist}
        parts: list[str] = []

        # Birth / death information
        if "birthDate" in attrs:
            parts.append(f"was born on {attrs['birthDate']}")
        elif "birthYear" in attrs:
            parts.append(f"was born in {attrs['birthYear']}")
        if "birthPlace" in attrs:
            parts.append(f"was born in {attrs['birthPlace']}")
        if "deathDate" in attrs:
            parts.append(f"died on {attrs['deathDate']}")
        if "deathPlace" in attrs:
            parts.append(f"died in {attrs['deathPlace']}")

        # Basic descriptors
        if "origin" in attrs:
            parts.append(f"originates from {attrs['origin']}")
        if "nationality" in attrs:
            parts.append(f"is {attrs['nationality']}")
        if "occupation" in attrs:
            parts.append(f"is a {attrs['occupation']}")
        if "instrument" in attrs:
            parts.append(f"plays the {attrs['instrument']}")
        if "associatedBand/associatedMusicalArtist" in attrs:
            parts.append(f"is associated with {attrs['associatedBand/associatedMusicalArtist']}")
        if "recordLabel" in attrs:
            parts.append(f"is signed to {attrs['recordLabel']}")
        if "activeYearsStartYear" in attrs:
            parts.append(f"started their career in {attrs['activeYearsStartYear']}")
        if "activeYearsEndYear" in attrs:
            parts.append(f"ended their career in {attrs['activeYearsEndYear']}")

        # Genre handling with extra info
        if "genre" in attrs:
            genre = attrs["genre"]
            genre_phrase = f"performs {genre}"
            extra = extra_info_for(genre)
            if extra:
                genre_phrase += " (" + ", ".join(extra) + ")"
            parts.append(genre_phrase)

        # Country / location predicates (non‑artist entities)
        if "country" in attrs:
            parts.append(f"is in the country of {attrs['country']}")
        if "capital" in attrs:
            parts.append(f"has capital {attrs['capital']}")
        if "isPartOf" in attrs:
            parts.append(f"is part of {attrs['isPartOf']}")
        if "language" in attrs:
            parts.append(f"has language {attrs['language']}")
        if "officialLanguage" in attrs:
            parts.append(f"has official language {attrs['officialLanguage']}")

        # Fallback for any other predicates not covered above
        covered = {
            "birthDate","birthYear","birthPlace","deathDate","deathPlace","origin",
            "nationality","occupation","instrument","associatedBand/associatedMusicalArtist",
            "recordLabel","activeYearsStartYear","activeYearsEndYear","genre",
            "country","capital","isPartOf","language","officialLanguage"
        }
        for p, o in attrs.items():
            if p not in covered:
                parts.append(f"{p.replace('_', ' ')} {o}")

        # Assemble sentence for this subject
        if parts:
            sentence = f"{subj} " + ", ".join(parts) + "."
        else:
            sentence = f"{subj}."
        sentences.append(sentence)

    # Combine all subject sentences into one paragraph‑style output
    return " ".join(sentences)

# EVOLVE-BLOCK-END

